  const handleSwitchToDeal = async (targetDeal: Deal) => {
    if (!editingDeal) return;

    // 1. Capture the ID of the current "draft" deal to delete
    const draftId = editingDeal.id;

    // 2. Optimistically remove the draft from the UI list immediately
    setDeals(prev => prev.filter(d => d.id !== draftId));

    // 3. Switch the modal to the existing deal
    setEditingDeal(targetDeal);
