// Helper to process items coming FROM the database
const processIncomingItem = (item: any, tableName: string) => {
    const processed = { ...item };

    // Normalize timestamps: Ensure createdAt exists if created_at is present
    if (processed.created_at && !processed.createdAt) {
        processed.createdAt = processed.created_at;
    }

    if (tableName === 'Deals') {
        processed.photos = cleanArrayField(processed.photos, false).filter(Boolean);
        processed.dealType = Array.from(new Set(cleanArrayField(processed.dealType, true))).filter(Boolean);
        processed.logs = cleanArrayField(processed.logs, false).filter(Boolean);
    }

    if (tableName === 'Wholesalers') {
        processed.notes = cleanArrayField(processed.notes, false).filter(Boolean);
        if (typeof processed.properties === 'string') {
            try { processed.properties = JSON.parse(processed.properties); } catch { }
        }
        if (!Array.isArray(processed.properties)) processed.properties = [];
    }

    return processed;
};

  if (filterConfig.type !== 'All') {
      filtered = filtered.filter(d => {
          if (!d) return false;
          switch (filterConfig.type) {
              case 'Acquisition Manager': return d.acquisitionManager === filterConfig.value; 
              case 'Show Counter Offers Only': return d.offerDecision === 'Seller Counter-Offered'; 
              case 'Sub-Market': return d.subMarket === filterConfig.value;
              case 'Deal Type': return Array.isArray(d.dealType) && d.dealType.includes(filterConfig.value);
              case 'Listing Type': return d.listingType === filterConfig.value;
              case 'Contact Status': return d.contactStatus === filterConfig.value;
              case 'Offer Decision': return d.offerDecision === filterConfig.value;
              case 'Agent Name': return d.agentName === filterConfig.value;
              default: return true;
          }
      });
  }
  return filtered.sort((a, b) => {
      if (pipelineSort === 'Price High-Low') return (b.listPrice || 0) - (a.listPrice || 0);
      if (pipelineSort === 'Price Low-High') return (a.listPrice || 0) - (b.listPrice || 0);

      // Robust Date Parsing: Check both camelCase and snake_case
      const getTimestamp = (d: any) => {
          const val = d.createdAt || d.created_at;
          return val ? new Date(val).getTime() : 0;
      };

      const dateA = getTimestamp(a);
      const dateB = getTimestamp(b);

      if (pipelineSort === 'Date Oldest') return dateA - dateB;

      // Date Newest (Default)
      return dateB - dateA;
  });
};

