    };
    // RESTORED: Fields are now saved to DB correctly based on user feedback
    try {
        const saved = await api.save(updatedDeal, 'Deals');
        if (saved) {
            setDeals(prev => {
                const exists = prev.some(d => d.id === saved.id);
