             {activeView === 'wholesalers' && (
                 <div className="w-full">
                     <PageNavBar title="Wholesaler Database" icon={<Briefcase/>} searchValue={wholesalerSearch} onSearchChange={setWholesalerSearch} searchPlaceholder="Search wholesalers..." tabs={WHOLESALER_STATUS_TABS.map(tab => ({ ...tab, count: tab.id === 'All Wholesalers' ? filteredWholesalersBySearch.length : filteredWholesalersBySearch.filter(w => w.status === tab.id).length }))} activeTab={wholesalerStage} onTabChange={setWholesalerStage} onToggleFilter={() => setShowFilterMenu(!showFilterMenu)} isFilterOpen={showFilterMenu} isFilterActive={filterConfig.type !== 'All'} filterContent={<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4"><div className="space-y-1"><label className="text-xs font-bold text-gray-500 uppercase">Wholesaler Type</label><select className="w-full text-sm bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded p-2" onChange={e => { if (e.target.value) setFilterConfig({type: 'Wholesaler Type', value: e.target.value}); else setFilterConfig({type: 'All', value: ''}); }} value={filterConfig.type === 'Wholesaler Type' ? filterConfig.value : ''}><option value="">All Types</option><option value="Acquisitions">Acquisitions</option><option value="Dispositions">Dispositions</option><option value="Acq & Dispo">Acq & Dispo</option></select></div><div className="col-span-full flex justify-end"><button onClick={() => setFilterConfig({ type: 'All', value: '' })} className="text-sm text-red-500 hover:underline">Clear Filters</button></div></div>} sortOptions={[{ value: 'A-Z', label: 'A to Z' }, { value: 'Z-A', label: 'Z to A' }, { value: 'Last Contacted', label: 'Last Contacted' }, { value: 'Next Follow-Up', label: 'Next Follow-Up' }]} sortValue={wholesalerSort} onSortChange={setWholesalerSort} actionLabel="Add Wholesaler" onAction={handleAddWholesaler} />
                     <div className="max-w-full mx-auto p-4 md:p-8">
                         <div className="grid md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                             {sortedWholesalers.length > 0 ? sortedWholesalers.map(wholesaler => (
                                 <WholesalerCard key={wholesaler.id} wholesaler={wholesaler} onEdit={(w) => { setEditingWholesaler(w); setShowAddWholesalerModal(true); }} onDelete={handleDeleteWholesaler} />
                             )) : (
                                 <div className="col-span-full text-center text-gray-500 py-10 border border-gray-200 dark:border-gray-800 rounded-lg bg-gray-100 dark:bg-gray-800/20">No wholesalers found matching your criteria.</div>
                             )}
                         </div>
                     </div>
                 </div>
             )}
             {activeView === 'contacts' && (
                 <div className="w-full h-full">
                     <ContactsManager contacts={contacts} setContacts={setContacts} />
                 </div>
             )}
             {activeView === 'buyers' && (
                 <div className="w-full">
                     <PageNavBar title="Buyer Database" icon={<Users/>} searchValue={buyerSearch} onSearchChange={setBuyerSearch} searchPlaceholder="Search buyers..." tabs={BUYER_STATUS_TABS.map(tab => ({ ...tab, count: tab.id === 'All Buyers' ? filteredBuyersBySearch.length : filteredBuyersBySearch.filter(b => b.status && b.status.includes(tab.id)).length }))} activeTab={buyerStage} onTabChange={setBuyerStage} onToggleFilter={() => setShowFilterMenu(!showFilterMenu)} isFilterOpen={showFilterMenu} isFilterActive={filterConfig.type !== 'All'} filterContent={<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4"><div className="space-y-1"><label className="text-xs font-bold text-gray-500 uppercase">Status</label><select className="w-full text-sm bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded p-2" onChange={e => { if(e.target.value) setFilterConfig({type: 'Buyer Status', value: e.target.value}); else setFilterConfig({type: 'All', value: ''}); }} value={filterConfig.type === 'Buyer Status' ? filterConfig.value : ''}><option value="">All Statuses</option><option value="VIP Buyer">VIP Buyer</option><option value="Repeat Buyer">Repeat Buyer</option><option value="Vetted Buyer">Vetted Buyer</option><option value="New Lead">New Lead</option></select></div><div className="space-y-1"><label className="text-xs font-bold text-gray-500 uppercase">Target Location</label><input type="text" className="w-full text-sm bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded p-2 focus:border-blue-500 outline-none" placeholder="Zip, City, or County..." value={filterConfig.type === 'Target Location' ? filterConfig.value : ''} onChange={e => { if (e.target.value) setFilterConfig({type: 'Target Location', value: e.target.value}); else setFilterConfig({type: 'All', value: ''}); }} /></div><div className="space-y-1"><label className="text-xs font-bold text-gray-500 uppercase">Sort By</label><select className="w-full text-sm bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded p-2" value={buyerSort} onChange={e => setBuyerSort(e.target.value)}><option value="Date Added - Newest">Date Added - Newest</option><option value="Date Added - Oldest">Date Added - Oldest</option><option value="A-Z">A to Z</option><option value="Z-A">Z to A</option><option value="Properties Bought">Properties Bought</option></select></div><div className="col-span-full flex justify-end"><button onClick={() => { setFilterConfig({ type: 'All', value: '' }); setBuyerSort('Date Added - Newest'); }} className="text-sm text-red-500 hover:underline">Clear Filters</button></div></div>} actionLabel="Add Buyer" onAction={handleAddBuyer} />
                     <div className="max-w-full mx-auto p-4 md:p-8">
                         <div className="grid md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                             {sortedBuyers.length > 0 ? sortedBuyers.map(buyer => (
                                 <BuyerCard key={buyer.id} buyer={buyer} onEdit={(b) => { setEditingBuyer(b); setShowAddBuyerModal(true); }} onDelete={handleDeleteBuyer} onUpdate={handleUpdateBuyer} />
                             )) : (
                                 <div className="col-span-full text-center text-gray-500 py-10 border border-gray-200 dark:border-gray-800 rounded-lg bg-gray-100 dark:bg-gray-800/20">No buyers found matching your filters.</div>
                             )}
                         </div>
                     </div>
                 </div>
             )}
             {activeView === 'calculator' && (<div className="max-w-3xl mx-auto p-4 md:p-8"><h2 className="text-2xl font-bold mb-6 flex items-center gap-2 text-purple-600 dark:text-purple-400"><Calculator/> Deal Analyzer</h2><div className="bg-white dark:bg-gray-800 p-6 rounded-xl shadow-lg border border-gray-200 dark:border-gray-700 space-y-4"><div className="grid grid-cols-2 gap-4"><div><label className="text-xs uppercase font-bold text-gray-500">ARV</label><input type="number" className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded p-3" value={calcData.arv} onChange={e => setCalcData({...calcData, arv: Number(e.target.value)})} /></div><div><label className="text-xs uppercase font-bold text-gray-500">Repairs</label><input type="number" className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded p-3" value={calcData.repairs} onChange={e => setCalcData({...calcData, repairs: Number(e.target.value)})} /></div><div><label className="text-xs uppercase font-bold text-gray-500">Wholesale Fee</label><input type="number" className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded p-3" value={calcData.fee} onChange={e => setCalcData({...calcData, fee: Number(e.target.value)})} /></div><div className="flex items-center"><label className="flex items-center gap-2 cursor-pointer"><input type="checkbox" checked={calcData.isDoubleClose} onChange={e => setCalcData({...calcData, isDoubleClose: e.target.checked})} className="w-5 h-5 rounded" /><span className="text-sm font-bold dark:text-white">Double Close?</span></label></div></div><div className="pt-4 border-t border-gray-200 dark:border-gray-700 mt-4"><div className="text-center"><div className="text-sm text-gray-500 uppercase font-bold">Max Allowable Offer (MAO)</div><div className="text-4xl font-bold text-green-600 dark:text-green-400">{formatCurrency(mao)}</div><div className="text-xs text-gray-400 mt-1">70% Rule - Repairs - Fee {calcData.isDoubleClose ? '- Costs' : ''}</div></div></div></div></div>)}
             {activeView === 'calendar' && (<div className="w-full h-full"><CalendarView agents={agents} buyers={buyers} onUpdateAgent={handleUpdateAgent} onUpdateBuyer={(id, updates) => handleUpdateBuyer(String(id), updates)} onViewAgent={(agent) => setViewingAgent(agent)} onViewBuyer={(buyer) => { setEditingBuyer(buyer); setShowAddBuyerModal(true); }} /></div>)}
        </main>
      </div>

      {importFile && (<ImportMapModal file={importFile} onClose={() => setImportFile(null)} onImport={async (d) => { const saved = await api.saveBatch(d,'Deals'); if(saved) setDeals(prev=>[...prev,...saved]); }} />)}
      {importBuyerFile && (<ImportBuyerMapModal file={importBuyerFile} onClose={() => setImportBuyerFile(null)} onImport={async (importedBuyers, overwrite) => {
          const saved = await api.saveBatch(importedBuyers, 'Buyers');
          if(saved) {
              setBuyers(prevBuyers => {
                  const newIds = new Set(saved.map((s:any) => s.id));
                  const oldBuyers = prevBuyers.filter(b => !newIds.has(b.id));
                  return [...oldBuyers, ...saved];
              });
          }
          setImportBuyerFile(null);
      }} />)}
      {importAgentFile && (<ImportAgentMapModal file={importAgentFile} onClose={() => setImportAgentFile(null)} onImport={async (a) => { const saved = await api.saveBatch(a,'Agents'); if(saved) setAgents(prev=>[...prev,...saved]); }} />)}

      {showAddAgentModal && (<AddAgentModal onClose={() => setShowAddAgentModal(false)} onSave={handleAddAgent} brokerages={brokerages} agents={agents} />)}

      {showAddWholesalerModal && editingWholesaler && (<EditWholesalerModal wholesaler={editingWholesaler} onClose={() => { setShowAddWholesalerModal(false); setEditingWholesaler(null); }} onSave={handleSaveWholesaler} onDelete={handleDeleteWholesaler} currentUser={currentUser} deals={deals} onOpenDeal={(d) => { setEditingWholesaler(null); setShowAddWholesalerModal(false); setDealModalZIndex('z-[160]'); setEditingDeal(d); }} onNavigate={handleWholesalerNavigate} hasNext={sortedWholesalers.indexOf(editingWholesaler) < sortedWholesalers.length - 1} hasPrevious={sortedWholesalers.indexOf(editingWholesaler) > 0} onMoveToAgent={() => handleMoveWholesalerToAgent(editingWholesaler)} onMoveToBuyer={() => handleMoveWholesalerToBuyer(editingWholesaler)} />)}
      {/* FIXED: currentUser prop added to ensure activity log name correctly renders */}
      {showAddBuyerModal && editingBuyer && (<EditBuyerModal buyer={editingBuyer} onClose={() => { setShowAddBuyerModal(false); setEditingBuyer(null); }} onSave={handleSaveBuyer} currentUser={currentUser} deals={deals} onOpenDeal={(d) => { setEditingBuyer(null); setShowAddBuyerModal(false); setDealModalZIndex('z-[160]'); setEditingDeal(d); }} onNavigate={handleBuyerNavigate} hasNext={sortedBuyers.indexOf(editingBuyer) < sortedBuyers.length - 1} hasPrevious={sortedBuyers.indexOf(editingBuyer) > 0} allBuyers={buyers} onSwitchToBuyer={(b) => setEditingBuyer(b)} onMoveToAgent={() => handleMoveBuyerToAgent(editingBuyer)} onMoveToWholesaler={() => handleMoveBuyerToWholesaler(editingBuyer)} zIndex="z-[140]" />)}
      {showSettings && currentUser && (<SettingsModal onClose={() => setShowSettings(false)} user={currentUser} onUpdateUser={handleUpdateUserProfile} onLogout={handleLogout} onOpenImportDeals={() => { setShowSettings(false); document.getElementById('import-deals')?.click(); }} onOpenImportBuyers={() => { setShowSettings(false); document.getElementById('import-buyers')?.click(); }} onOpenImportAgents={() => { setShowSettings(false); document.getElementById('import-agents')?.click(); }} theme={theme} setTheme={setTheme} isSidebarCollapsed={isSidebarCollapsed} setSidebarCollapsed={setSidebarCollapsed} agentsCount={agents.length} buyersCount={buyers.length} onSyncAgentPhotos={handleSyncAgentPhotos} isSyncingPhotos={isSyncingPhotos} onSyncAgentDetails={handleSyncAgentDetails} isSyncingDetails={isSyncingDetails} />)}

      <input type="file" id="import-deals" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
      <input type="file" id="import-buyers" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleBuyerFileUpload} />
      <input type="file" id="import-agents" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleAgentFileUpload} />

      {viewingAgent && (<AgentProfileModal agent={viewingAgent} onClose={() => setViewingAgent(null)} onUpdateAgent={handleUpdateAgent} currentUser={currentUser} deals={deals} onOpenDeal={(d) => { setDealModalZIndex('z-[160]'); setEditingDeal(d); }} zIndex={agentModalZIndex} onNavigate={handleAgentNavigate} hasNext={sortedAgents.indexOf(viewingAgent) < sortedAgents.length - 1} hasPrevious={sortedAgents.indexOf(viewingAgent) > 0} onMoveToBuyer={() => handleMoveAgentToBuyer(viewingAgent)} onMoveToWholesaler={() => handleMoveAgentToWholesaler(viewingAgent)} />)}
      {editingAgent && (<AgentProfileModal agent={editingAgent} onClose={() => setEditingAgent(null)} onUpdateAgent={handleUpdateAgent} currentUser={currentUser} deals={deals} onOpenDeal={(d) => { setDealModalZIndex('z-[160]'); setEditingDeal(d); }} onDelete={async (id) => { const s = await api.delete(id, 'Agents'); if(s) { setAgents(prev => prev.filter(a => a.id !== id)); setEditingAgent(null); }}} zIndex={agentModalZIndex} onNavigate={handleAgentNavigate} hasNext={sortedAgents.indexOf(editingAgent) < sortedAgents.length - 1} hasPrevious={sortedAgents.indexOf(editingAgent) > 0} onMoveToBuyer={() => handleMoveAgentToBuyer(editingAgent)} onMoveToWholesaler={() => handleMoveAgentToWholesaler(editingAgent)} />)}
      {editingDeal && (
        <EditDealModal 
            deal={editingDeal} 
            setDeal={setEditingDeal} 
            onSave={handleSaveEdit} 
            onClose={handleCloseEditModal} 
            onViewAgent={handleViewAgentProfile} 
            agentSuggestions={agentSuggestions} 
            brokerageSuggestions={brokerageSuggestions} 
            showAgentSuggestions={showAgentSuggestions} 
            showBrokerageSuggestions={showBrokerageSuggestions} 
            onAgentLookup={handleAgentLookup} 
            onBrokerageLookup={handleBrokerageLookup} 
            onSelectAgent={selectAgent} 
            onSelectBrokerage={selectBrokerage} 
            agents={agents} 
            onUpdateAgent={handleUpdateAgent} 
            onAddNewAgent={async (name) => { 
                const newAgent: Agent = { id: generateId(), name: name || '', phone: '', email: '', brokerage: '', notes: [`${getLogTimestamp()}: Created from Deal Modal`] }; 
                const saved = await api.save(newAgent, 'Agents'); 
                if(saved) { 
                    setAgents(prev => [...prev, saved]); 
                    setEditingAgent(saved); 
                    setAgentModalZIndex('z-[160]'); 
                } 
            }} 
            currentUser={currentUser} 
            onNavigate={handleNavigate} 
            hasNext={editingDealIndex !== -1 && editingDealIndex < orderedDeals.length - 1} 
            hasPrevious={editingDealIndex !== -1 && editingDealIndex > 0} 
            onUpdate={updateDeal} 
            buyers={buyers} 
            onViewBuyer={(id) => { 
                const b = buyers.find(buyer => buyer.id === id); 
                if(b) { setEditingBuyer(b); setShowAddBuyerModal(true); } 
            }} 
            zIndex={dealModalZIndex} 
            allDeals={deals}
            onSwitchToDeal={handleSwitchToDeal}
        />
      )}

      {showOnlineUsersModal && (
          <div className="fixed inset-0 bg-black/60 z-[200] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setShowOnlineUsersModal(false)}>
              <div className="bg-white dark:bg-gray-900 rounded-xl w-full max-w-sm border border-gray-200 dark:border-gray-700 shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 flex justify-between items-center">
                      <h3 className="font-bold text-gray-900 dark:text-white flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div> Online Users ({onlineUsersCount})</h3>
                      <button onClick={() => setShowOnlineUsersModal(false)}><X size={18} className="text-gray-500 hover:text-gray-900 dark:hover:text-white"/></button>
                  </div>
                  <div className="max-h-[300px] overflow-y-auto p-2">
                      {onlineUsersList.map(user => (
                          <div key={user.id} className="flex items-center gap-3 p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg transition-colors">
                              <div className="w-8 h-8 rounded-full bg-gray-200 dark:bg-gray-700 overflow-hidden shrink-0">
                                  {user.photo ? <img src={user.photo} className="w-full h-full object-cover"/> : <User size={16} className="text-gray-400 m-auto mt-2"/>}
                              </div>
                              <div>
                                  <div className="text-sm font-bold text-gray-900 dark:text-white">{user.name}</div>
                                  <div className="text-xs text-blue-500 dark:text-blue-400">{user.position}</div>
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}
